import{_ as a,o as s,c as e,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相 PFC 内层电流环","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 PFC 内层电流环","tags":["power-electronics"],"status":"learning","summary":"功率因数校正（power factor correction / PFC）的电流环（current loop）是内层快速环。它的任务是让实际电感电流（inductor current / iL）跟踪电流参考 `i_ref`。"},"headers":[],"relativePath":"content/power/concepts/single-phase-pfc-current-loop.md","filePath":"content/power/concepts/single-phase-pfc-current-loop.md","lastUpdated":1782835746000}'),t={name:"content/power/concepts/single-phase-pfc-current-loop.md"};function n(p,i,o,r,h,c){return s(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="概念-单相-pfc-内层电流环" tabindex="-1">概念：单相 PFC 内层电流环 <a class="header-anchor" href="#概念-单相-pfc-内层电流环" aria-label="Permalink to &quot;概念：单相 PFC 内层电流环&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）的电流环（current loop）是内层快速环。它的任务是让实际电感电流（inductor current / iL）跟踪电流参考 <code>i_ref</code>。</p><p>上一节电压环给出电流参考幅值，本节关注：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>error = i_ref - iL</span></span>
<span class="line"><span>占空比命令 D = current_controller(error)</span></span></code></pre></div><p>本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。维护本学习仓库时，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）的 PFC 前级要让输入电流跟着参考波形走。只有电压环不够，因为电压环只知道“要多少电流幅值”，不知道电感电流每个控制周期是否真的跟上了。</p><p>电流环的质量直接影响：</p><ul><li>输入电流畸变。</li><li>功率因数。</li><li>过流风险。</li><li>PFC 对负载变化和电网变化的响应。</li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>电压环像告诉你“目标速度是多少”，电流环像脚下的油门控制。参考电流在一个工频周期内不断变化，电流环要快速推着电感电流追上它。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>电流误差：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>e_i[k] = i_ref[k] - iL[k]</span></span></code></pre></div><p>比例积分控制器（proportional-integral controller / PI）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>u[k] = Kp * e_i[k] + integral[k] + feedforward[k]</span></span>
<span class="line"><span>integral[k+1] = integral[k] + Ki * e_i[k] * Ts</span></span>
<span class="line"><span>D[k] = clamp(0.5 + u[k] / Vbus, Dmin, Dmax)</span></span></code></pre></div><p>简化电感模型：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>diL/dt = vL / L</span></span>
<span class="line"><span>vL ≈ (D - 0.5) * Vbus - R * iL</span></span></code></pre></div><p>这里的占空比命令（duty command / D）只是平均模型命令，不是开关级 PWM 波形。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_current_loop.py</span></span></code></pre></div><p>对比一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_current_loop.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">current</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rms</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">reference </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_current_loop_3a.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_current_loop.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">current</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rms</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">reference </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_current_loop_8a.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察：</p><ul><li>电流参考 <code>iref</code> 是正弦波。</li><li>实际电感电流 <code>iL</code> 应跟随 <code>iref</code>。</li><li>跟踪误差 <code>e_i</code> 不应长期偏大。</li><li>占空比命令 <code>D</code> 应在限幅内变化。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实固件里，电流环通常在控制 ISR 中运行：</p><ul><li>读取 ADC 采样的电感电流。</li><li>计算 <code>i_ref - iL</code>。</li><li>执行 PI 或 PR 等控制器。</li><li>加入前馈、限幅、抗积分饱和。</li><li>更新脉宽调制（pulse-width modulation / PWM）比较值。</li></ul><p>工程阅读时重点找：电流采样在哪里更新、参考值在哪里传入、控制器输出如何限幅、PWM 何时更新。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：电压环输出电流幅值后，电流自然就会变成目标波形。<br> 正确理解：必须有内层电流环让实际电感电流跟踪参考。</p></li><li><p>错误理解：电流环越猛越好。<br> 正确理解：过高增益会导致噪声放大、占空比抖动和稳定性问题。</p></li><li><p>错误理解：平均模型等于真实开关波形。<br> 正确理解：平均模型用于理解控制趋势，真实 PWM 还会带来开关纹波、采样延迟和调制限制。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释电流环（current loop）的输入、输出和作用。</li><li>能在图中指出 <code>iref</code>、<code>iL</code>、<code>e_i</code> 和 <code>D</code>。</li><li>能解释占空比命令（duty command / D）为什么需要限幅。</li><li>能解释均方根值（root mean square / RMS） tracking error 表示什么。</li><li>能基于 <code>single_phase_pfc_current_loop.py</code> 的仿真图准备具体导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，电流参考 RMS 是多少 A？跟踪误差大约是多少？</li><li>把参考电流提高到 8 A 后，占空比命令有什么变化？</li><li>如果占空比长时间撞到上限，可能是控制参数问题、输入电压问题，还是负载过重问题？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pfc_current_loop.py</code> 看到 <code>iL</code> 跟踪 <code>iref</code>，但仍有误差。公司 PFC 电流环常用 PI、PR 还是其他控制器？</li><li>图中占空比命令有限幅。真实工程里 PFC 电流环的占空比限幅和过流保护如何配合？</li><li>本节用了平均模型。公司调试 PFC 电流环时通常先看平均模型、Simulink 开关模型，还是直接看示波器波形？</li></ul>`,39)])])}const u=a(t,[["render",n]]);export{k as __pageData,u as default};
